// /frontend/src/components/SearchSection.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";

// LocalStorage keys (scoped to this component)
const LS_LAST_PLACE = "weatherapp:lastPlace";
const LS_FAVORITES = "weatherapp:favorites";

function isFiniteNum(n) { return typeof n === "number" && isFinite(n); }
function clamp(n, min, max) { return Math.max(min, Math.min(max, n)); }
function normPlace(p) {
  const lat = isFiniteNum(p?.lat) ? clamp(p.lat, -85, 85) : null;
  const lon = isFiniteNum(p?.lon) ? clamp(p.lon, -180, 180) : null;
  const name = (p?.name || p?.display || "").toString().trim();
  return lat == null || lon == null || !name ? null : { name, lat, lon };
}
function sameLoc(a, b, eps = 1e-6) {
  if (!a || !b) return false;
  return Math.abs(a.lat - b.lat) <= eps && Math.abs(a.lon - b.lon) <= eps;
}

// Simple debounce hook
function useDebounce(value, ms = 250) {
  const [v, setV] = useState(value);
  useEffect(() => {
    const id = setTimeout(() => setV(value), ms);
    return () => clearTimeout(id);
  }, [value, ms]);
  return v;
}

export default function SearchSection({
  className = "",
  placeholder = "Search any city…",
  defaultValue = "",
  onSelect = () => {},   // optional: parent gets {name, lat, lon}
}) {
  // Input + results state
  const [q, setQ] = useState(defaultValue);
  const [results, setResults] = useState([]);
  const [open, setOpen] = useState(false);
  const [loading, setLoading] = useState(false);
  const [err, setErr] = useState("");
  const [active, setActive] = useState(0);

  // Persistence state
  const [favorites, setFavorites] = useState(() => {
    try {
      const raw = localStorage.getItem(LS_FAVORITES);
      const arr = raw ? JSON.parse(raw) : [];
      return Array.isArray(arr) ? arr.filter(Boolean) : [];
    } catch { return []; }
  });

  const [lastPlace, setLastPlace] = useState(() => {
    try {
      const raw = localStorage.getItem(LS_LAST_PLACE);
      const obj = raw ? JSON.parse(raw) : null;
      return normPlace(obj);
    } catch { return null; }
  });

  // On mount: if we have a last place, emit it to parent and show in input
  useEffect(() => {
    if (lastPlace) {
      setQ(lastPlace.name);
      onSelect?.(lastPlace);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // run once

  // Persist favorites when changed
  useEffect(() => {
    try { localStorage.setItem(LS_FAVORITES, JSON.stringify(favorites)); } catch {}
  }, [favorites]);

  // Debounced search
  const debouncedQ = useDebounce(q, 300);

  useEffect(() => {
    let abort = new AbortController();
    async function run() {
      setErr("");
      if (!debouncedQ || debouncedQ.trim().length < 2) {
        setResults([]);
        return;
      }
      setLoading(true);
      try {
        const url = new URL("https://nominatim.openstreetmap.org/search");
        url.searchParams.set("format", "jsonv2");
        url.searchParams.set("addressdetails", "1");
        url.searchParams.set("limit", "8");
        url.searchParams.set("q", debouncedQ.trim());

        const res = await fetch(url.toString(), {
          signal: abort.signal,
          headers: { "Accept-Language": "en" },
        });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = await res.json();
        const mapped = (Array.isArray(data) ? data : []).map((d) => {
          const city = d.address?.city || d.address?.town || d.address?.village || d.address?.hamlet || d.address?.municipality || "";
          const state = d.address?.state || d.address?.region || "";
          const country = d.address?.country || "";
          const name = city ? `${city}${state ? ", " + state : ""}, ${country}` : d.display_name;
          return {
            name,
            lat: parseFloat(d.lat),
            lon: parseFloat(d.lon),
            _full: d.display_name,
          };
        });
        setResults(mapped);
        setOpen(true);
        setActive(0);
      } catch (e) {
        if (e.name !== "AbortError") {
          setErr("Search failed. Try again.");
          setResults([]);
        }
      } finally {
        setLoading(false);
      }
    }
    run();
    return () => abort.abort();
  }, [debouncedQ]);

  // Outside-click to close
  const boxRef = useRef(null);
  useEffect(() => {
    const onDocClick = (e) => {
      if (!boxRef.current?.contains(e.target)) setOpen(false);
    };
    document.addEventListener("mousedown", onDocClick);
    return () => document.removeEventListener("mousedown", onDocClick);
  }, []);

  function choose(idx) {
    const item = results[idx];
    if (!item) return;
    const place = normPlace(item);
    if (!place) return;
    setQ(place.name);
    setOpen(false);
    setLastPlace(place);
    try { localStorage.setItem(LS_LAST_PLACE, JSON.stringify(place)); } catch {}
    onSelect?.(place);
  }

  // favorites actions
  function addFavoriteFromLast() {
    if (!lastPlace) return;
    setFavorites((prev) => {
      const exists = prev.some((f) => sameLoc(f, lastPlace));
      if (exists) return prev;
      return [lastPlace, ...prev].slice(0, 12); // cap list
    });
  }
  function removeFavorite(idx) {
    setFavorites((prev) => prev.filter((_, i) => i !== idx));
  }
  function selectFavorite(f) {
    const place = normPlace(f);
    if (!place) return;
    setQ(place.name);
    setLastPlace(place);
    try { localStorage.setItem(LS_LAST_PLACE, JSON.stringify(place)); } catch {}
    onSelect?.(place);
  }

  function onKeyDown(e) {
    if (!open && (e.key === "ArrowDown" || e.key === "Enter")) {
      setOpen(true);
      return;
    }
    if (e.key === "ArrowDown") {
      e.preventDefault();
      setActive((i) => Math.min(i + 1, Math.max(0, results.length - 1)));
    } else if (e.key === "ArrowUp") {
      e.preventDefault();
      setActive((i) => Math.max(i - 1, 0));
    } else if (e.key === "Enter") {
      e.preventDefault();
      if (results.length > 0) choose(active);
    } else if (e.key === "Escape") {
      setOpen(false);
    }
  }

  const isLastInFavorites = useMemo(
    () => !!lastPlace && favorites.some((f) => sameLoc(f, lastPlace)),
    [favorites, lastPlace]
  );

  return (
    <div className={`w-full ${className}`}>
      {/* Search box + star for last selection */}
      <div ref={boxRef} className="relative w-full">
        <input
          value={q}
          onChange={(e) => setQ(e.target.value)}
          onFocus={() => results.length && setOpen(true)}
          onKeyDown={onKeyDown}
          placeholder={placeholder}
          className="w-full px-4 py-3 rounded-xl bg-black/60 text-white placeholder-gray-300 outline-none ring-1 ring-white/10 focus:ring-purple-500"
          aria-autocomplete="list"
          aria-expanded={open}
          aria-controls="search-suggest"
        />
        {/* Favorite toggle button for the *current* lastPlace */}
        <button
          type="button"
          onClick={addFavoriteFromLast}
          disabled={!lastPlace || isLastInFavorites}
          title={isLastInFavorites ? "Already in favorites" : "Add current city to favorites"}
          className={`absolute right-2 top-1/2 -translate-y-1/2 text-xs px-2 py-1 rounded-md ${
            isLastInFavorites ? "bg-purple-600/50 text-white" : "bg-black/50 text-white hover:bg-black/60"
          }`}
          style={{ border: "1px solid rgba(255,255,255,0.25)" }}
        >
          {isLastInFavorites ? "★" : "☆"}
        </button>

        {open && (
          <div
            id="search-suggest"
            className="absolute z-50 mt-2 w-full max-h-72 overflow-auto rounded-xl backdrop-blur-md bg-black/70 ring-1 ring-white/10"
          >
            {loading && (
              <div className="px-4 py-3 text-sm text-gray-200">Searching…</div>
            )}
            {!loading && err && (
              <div className="px-4 py-3 text-sm text-red-300">{err}</div>
            )}
            {!loading && !err && results.length === 0 && debouncedQ.length >= 2 && (
              <div className="px-4 py-3 text-sm text-gray-200">No matches.</div>
            )}
            {!loading &&
              results.map((r, i) => (
                <button
                  key={`${r.lat},${r.lon},${i}`}
                  onClick={() => choose(i)}
                  className={`w-full text-left px-4 py-3 text-sm text-white hover:bg-white/10 ${
                    i === active ? "bg-white/10" : ""
                  }`}
                >
                  <div className="font-medium">{r.name}</div>
                  <div className="text-xs text-gray-300 truncate">{r._full}</div>
                </button>
              ))}
          </div>
        )}
      </div>

      {/* Favorites chips row */}
      {favorites.length > 0 && (
        <div className="mt-2 flex gap-2 overflow-x-auto no-scrollbar pb-1">
          {favorites.map((f, idx) => (
            <div
              key={`${f.lat},${f.lon},${idx}`}
              className="shrink-0 flex items-center gap-2 px-3 py-1.5 rounded-xl text-xs bg-black/60 text-white ring-1 ring-white/10"
              title={f.name}
            >
              <button onClick={() => selectFavorite(f)} className="font-medium">
                {f.name}
              </button>
              <button
                onClick={() => removeFavorite(idx)}
                className="opacity-70 hover:opacity-100"
                aria-label="remove favorite"
                title="remove"
              >
                ×
              </button>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
